import{_ as t,o as e,c as o,a2 as l}from"./chunks/framework.BWuWLRhz.js";const g=JSON.parse('{"title":"28 · skill-creator 使用：用一个 skill 造你自己的 skill","description":"","frontmatter":{"head":[["meta",{"property":"og:site_name","content":"David Studio AI 编程指南"}]]},"headers":[],"relativePath":"claude-code/28-skill-creator.md","filePath":"claude-code/28-skill-creator.md"}'),i={name:"claude-code/28-skill-creator.md"};function d(a,s,c,n,r,p){return e(),o("div",null,[...s[0]||(s[0]=[l(`<h1 id="_28-·-skill-creator-使用-用一个-skill-造你自己的-skill" tabindex="-1">28 · skill-creator 使用：用一个 skill 造你自己的 skill <a class="header-anchor" href="#_28-·-skill-creator-使用-用一个-skill-造你自己的-skill" aria-label="Permalink to &quot;28 · skill-creator 使用：用一个 skill 造你自己的 skill&quot;">​</a></h1><blockquote><p>📚 <strong>系列导航</strong>：上一篇 [27 Skills 使用实例] 教你怎么用好别人造的 skill——装进来、让它自动触发、用得顺手。这一篇反过来：教你造自己的。而且不靠手搓，靠官方那个专门用来造 skill 的 skill——<code>skill-creator</code>。</p></blockquote><p>都说 <code>SKILL.md</code> 不就一个 markdown 文件嘛，自己手写就完了，犯得着再请个工具？</p><p>说句实话，这话只对了一半。<strong>文件确实简单，但「造一个能被准确触发的 skill」这件事一点都不简单</strong>——而手写翻车的，九成栽在同一个地方：<code>description</code> 写歪了，结果这 skill 永远叫不动。</p><p>我自己第一个手写的 skill 就是这么翻的。当时想做一个「生成符合团队规范的 commit message」的 skill，目录建好、正文写得明明白白，<code>description</code> 我随手填了句「Commit message helper」。结果呢？<strong>每次让 Claude 提交，它压根不理我那个 skill，自己按通用习惯写一版</strong>。我一口咬定是没装好，折腾半天 <code>/doctor</code>、重启、重装，全没用。后来才搞明白——<strong>问题不在「装没装上」，在「描述里没有用户会说的那些词」</strong>。这种坑，手写时你完全看不见，得有个东西逼你把它做对。</p><p><code>skill-creator</code> 就是那个东西。</p><p><strong>看完这一篇，你会拿到：</strong></p><ul><li>为什么手写 <code>SKILL.md</code> 看着省事、实际最容易踩坑，<code>skill-creator</code> 到底帮你做对了哪几件事</li><li><code>skill-creator</code> 的完整造 skill 流程：起脚手架 → 引导写 <code>name</code> / <code>description</code> / 正文 → 组织 <code>scripts</code> 和 <code>references</code> → 打包</li><li>全篇最值钱的一节：<code>description</code> 怎么写才能被准确触发（含触发场景关键词，还得「主动」一点）</li><li>个人 skill 和项目 skill 该落在哪个目录，谁能用到</li><li>一个能照着跑的动手实战：用 <code>skill-creator</code> 起一个最小 skill，并亲手验证它真的被触发了</li></ul><hr><h2 id="_01-反共识-手写-skill-md-不难-难的是「让它叫得动」" tabindex="-1">01 反共识：手写 <code>SKILL.md</code> 不难，难的是「让它叫得动」 <a class="header-anchor" href="#_01-反共识-手写-skill-md-不难-难的是「让它叫得动」" aria-label="Permalink to &quot;01 反共识：手写 \`SKILL.md\` 不难，难的是「让它叫得动」&quot;">​</a></h2><p>先把上一篇的底子接上。27 篇里你已经知道：一个 skill 就是一个目录，核心是里面那个 <code>SKILL.md</code>，顶上一段 YAML 写 <code>name</code> 和 <code>description</code>，下面是给 Claude 看的正文。官方文档原话：</p><blockquote><p>每个 skill 都需要一个 <code>SKILL.md</code> 文件，包含两部分：YAML frontmatter（在 <code>---</code> 标记之间）告诉 Claude 何时使用该 skill，以及包含 Claude 在调用该 skill 时遵循的说明的 markdown 内容。</p></blockquote><p>看着是不是特简单？建个文件夹、写个文件，齐活。所以新手第一反应都是：<strong>手写就行了，要什么工具</strong>。</p><p>这就是那个<strong>反共识的点</strong>：手写本身确实不难，<strong>难的是手写出来的 skill「叫不动」——你以为它会在该出场的时候自动出场，结果它一直在角落里睡觉</strong>。</p><p><strong>类比：填一张表单的「造工具向导」。</strong> 你装新软件时见过那种向导吧——它不让你对着空白配置文件瞎填，而是一页一页问你「这工具叫什么」「什么情况下该用它」「输入长啥样、输出要什么格式」，你回答几个问题，它在背后把目录结构、脚手架、各字段的位置全给你摆对。<code>skill-creator</code> 就是 skill 界的这种向导：<strong>你回答它几个问题，它把那些「手写时你根本想不到要管」的事替你做对</strong>。</p><p>具体它替你兜住了哪几个手写最容易翻的坑？看这张对照表——<strong>这是本节最该记住的</strong>：</p><table tabindex="0"><thead><tr><th>容易翻车的环节</th><th>❌ 纯手写常见结果</th><th>✅ <code>skill-creator</code> 帮你做对</th></tr></thead><tbody><tr><td><code>description</code></td><td>写成「Commit helper」这种，缺触发词，永远不触发</td><td>引导你写清「干什么 + 什么时候用」，含用户会说的关键词</td></tr><tr><td>目录结构</td><td>把脚本、参考文档全塞进 <code>SKILL.md</code>，又长又乱</td><td>帮你分到 <code>scripts/</code> <code>references/</code>，正文保持精简</td></tr><tr><td>触发验证</td><td>写完不知道到底触不触发，全靠玄学</td><td>给你测试用例，跑一遍看它到底叫不叫得动</td></tr><tr><td>改进</td><td>没触发只能干瞪眼，不知道改哪</td><td>有专门的描述优化环节，对着触发率调</td></tr></tbody></table><p>看出来没？<strong>手写翻的车，全是「你看不见所以没管」的事</strong>。<code>skill-creator</code> 的价值不是帮你打字（打字它没快多少），而是<strong>逼你把这几件隐形的事一件不落地做对</strong>。</p><blockquote><p>💡 一句话总结：手写 <code>SKILL.md</code> 不难，难在让它在该触发时真触发；<strong><code>skill-creator</code> 像个填表造工具的向导，把 <code>description</code>、目录、验证、改进这几件「手写时看不见」的事替你兜住</strong>。</p></blockquote><hr><h2 id="_02-skill-creator-是什么、怎么请它出场" tabindex="-1">02 <code>skill-creator</code> 是什么、怎么请它出场 <a class="header-anchor" href="#_02-skill-creator-是什么、怎么请它出场" aria-label="Permalink to &quot;02 \`skill-creator\` 是什么、怎么请它出场&quot;">​</a></h2><p>先给结论：<strong><code>skill-creator</code> 本身就是一个 skill，它的专长是「造别的 skill」</strong>。听着像绕口令，但逻辑很顺——既然 skill 是用来扩展 Claude 能力的，那「造 skill」这件重复性工作，本身就值得做成一个 skill。</p><p>它不是 Claude Code 自带就有的（不像 <code>/code-review</code>、<code>/debug</code> 那几个捆绑 skill），需要单独安装——把 skill 目录放到 <code>~/.claude/skills/</code>（个人全局）或项目的 <code>.claude/skills/</code>（只对这个项目生效），第 27 篇已讲过这套机制。官方插件市场（<code>claude-plugins-official</code>）里对应「创建插件」的工具包叫 <code>plugin-dev</code>，<code>skill-creator</code> 是独立发布的 skill，安装方式是直接克隆或下载目录到 skills 路径：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 把 skill-creator 目录放到个人 skills 目录</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> skill-creator</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.claude/skills/</span></span></code></pre></div><p><strong>预期</strong>：放好后，<code>/skills</code> 列表里能看到 <code>skill-creator</code>，描述写着「Create new skills, modify and improve existing skills...」。</p><p>装好之后，请它出场有两种姿势，<strong>跟 27 篇讲的「用 skill」一模一样</strong>：</p><p><strong>姿势一：直接喊名字（明确指令）。</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/skill-creator</span></span></code></pre></div><p><strong>姿势二：用大白话说你要干啥（让它自动触发）。</strong> 这也是更常用的一种——因为 <code>skill-creator</code> 的 <code>description</code> 写得很「全」，你说「我想做一个 skill 来干 XX」它就接住了：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>我想做一个 skill，每次帮我把 git 改动总结成一条规范的 commit message</span></span></code></pre></div><p>不管哪种姿势，接下来它都不会闷头给你甩一个文件，而是<strong>像向导一样开始问你问题</strong>。官方那个 <code>skill-creator</code> 的说明里，第一步就叫「Capture Intent（捕捉意图）」，它会问你这么几件事：</p><blockquote><ol><li>这个 skill 要让 Claude 能干什么？</li><li>它应该在什么时候触发？（用户会用哪些说法 / 在什么场景）</li><li>期望的输出格式是什么？</li><li>要不要建测试用例来验证它能正常工作？</li></ol></blockquote><p>注意第 2 问——<strong>「什么时候触发」它会专门问你一遍</strong>。这就是它跟手写最大的不同：手写时这个问题没人逼你回答，你随手糊一个描述就过去了；<code>skill-creator</code> 把它当头等大事，因为它知道<strong>这一问答不好，造出来的 skill 就是个废物</strong>。</p><p><strong>类比：婚礼策划师接单先把你问个底朝天。</strong> 靠谱的策划不会上来就甩方案，他先问「预算多少」「请多少人」「想要中式还是户外」「有没有忌讳」。把这些问透了，出的方案才贴你的需求，而不是套个模板了事。<code>skill-creator</code> 的「Capture Intent」就是这道「问需求」工序——<strong>先把你要什么问明白，再动手攒 skill</strong>。</p><blockquote><p>💡 一句话总结：<code>skill-creator</code> 是个「造 skill 的 skill」，从官方插件市场装（需魔法上网）；喊 <code>/skill-creator</code> 或大白话说需求都能唤出它，<strong>它出场第一件事是反过来问你问题，尤其会专门问「这 skill 什么时候该触发」</strong>。</p></blockquote><hr><h2 id="_03-它替你走完的完整流程" tabindex="-1">03 它替你走完的完整流程 <a class="header-anchor" href="#_03-它替你走完的完整流程" aria-label="Permalink to &quot;03 它替你走完的完整流程&quot;">​</a></h2><p><code>skill-creator</code> 不是只帮你生成一个文件就撒手，它会<strong>陪你走完造 skill 的一整条流水线</strong>。把它的流程拆开看，你就知道每一步它在帮你兜什么。</p><p>官方 <code>skill-creator</code> 把整个过程概括成一个循环，我给你翻成大白话：</p><ol><li><strong>想清楚要干啥</strong>：先跟你聊明白这 skill 做什么、大概怎么做（就是上一节的「Capture Intent」）。</li><li><strong>写初稿</strong>：根据你的回答，填好 <code>name</code>、<code>description</code> 和正文，生成 <code>SKILL.md</code>。</li><li><strong>建测试用例</strong>：写 2-3 个「真实用户会说的话」当测试 prompt，问你「这几个测试像不像样，要不要加」。</li><li><strong>跑一遍 + 评估</strong>：拿这些 prompt 实际跑，让你看结果好不好——既看「输出对不对」，也看「该触发的有没有触发」。</li><li><strong>照反馈改</strong>：根据你的评价和测试结果回头改 skill，<strong>改完再跑一轮</strong>，直到你满意。</li><li><strong>（可选）优化描述</strong>：专门有个环节优化 <code>description</code>，把触发准确率往上调。</li><li><strong>打包</strong>：最后把整个 skill 目录打成一个 <code>.skill</code> 文件，方便你分发或安装。</li></ol><p>看出这条流水线的门道没？<strong>手写时你只做了第 2 步（写个文件），后面 3-7 全跳过了</strong>——所以你的 skill 触不触发全凭运气，触不动也不知道怎么改。<code>skill-creator</code> 的价值就在于它<strong>把 2 之后那几步当成必修课</strong>，尤其是「跑测试看触发」和「照反馈改」这个循环。</p><p>这里穿插一个<strong>它帮你做对的目录结构</strong>。官方文档「添加支持文件」一节给的目录示例是这样的：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>my-skill/</span></span>
<span class="line"><span>├── SKILL.md           # 主要说明（必需）</span></span>
<span class="line"><span>├── reference.md       # 详细参考文档，按需加载</span></span>
<span class="line"><span>├── examples.md        # 示例输出，按需加载</span></span>
<span class="line"><span>└── scripts/</span></span>
<span class="line"><span>    └── helper.py      # Claude 可以执行的脚本</span></span></code></pre></div><p>关键认知：<strong><code>SKILL.md</code> 要短，重的东西往外放</strong>。官方原话点得很透：</p><blockquote><p>将 <code>SKILL.md</code> 保持在 500 行以下。将详细的参考资料移到单独的文件中。</p></blockquote><p>为啥要这么分？因为 skill 一旦触发，<code>SKILL.md</code> 的内容会<strong>整段进上下文、并在整个会话里赖着不走</strong>——每一行都是重复的 token 成本。而 <code>scripts/</code> 里的脚本是「执行但不加载」、<code>references/</code> 里的文档是「需要时才读」。<strong>手写最容易犯的错，就是把一份三百行的 API 文档直接糊进 <code>SKILL.md</code></strong>，又占上下文又乱。<code>skill-creator</code> 会引导你把这些分门别类放对地方——正文只留「干什么、去哪找」，重资料挪进 <code>references/</code>，可执行的活儿挪进 <code>scripts/</code>。</p><p><strong>类比：写一本书的目录页和附录。</strong> 你不会把所有内容都堆在目录页上，目录页只写「第几章讲什么、在哪一页」，详细内容在正文和附录里。<code>SKILL.md</code> 就是那张目录页——<strong>它告诉 Claude「有哪些料、什么时候去翻哪一份」，料本身放在 <code>references/</code> 和 <code>scripts/</code> 里</strong>。</p><blockquote><p>💡 一句话总结：<code>skill-creator</code> 陪你走的是「想清楚 → 写初稿 → 跑测试看触发 → 照反馈改 → 优化描述 → 打包」一整条流水线；<strong>手写往往只做了第二步，它把后面那几步补全了</strong>，还会引导你把重资料分到 <code>references/</code> 和 <code>scripts/</code>、让 <code>SKILL.md</code> 保持精简。</p></blockquote><hr><h2 id="_04-全篇最值钱的一节-description-怎么写才叫得动" tabindex="-1">04 全篇最值钱的一节：<code>description</code> 怎么写才叫得动 <a class="header-anchor" href="#_04-全篇最值钱的一节-description-怎么写才叫得动" aria-label="Permalink to &quot;04 全篇最值钱的一节：\`description\` 怎么写才叫得动&quot;">​</a></h2><p>如果这篇你只记一件事，记这件：<strong><code>description</code> 是决定一个 skill 触不触发的「总开关」</strong>。</p><p>为什么是它？因为 Claude 在每次对话里，看到的不是你 skill 的全文——<strong>它先看到的只是一串「skill 名字 + description」的清单</strong>，然后根据这个 description 判断「这次该不该把这个 skill 调出来」。description 写得对不对，直接决定它会不会被想起来。官方在「Skill 未触发」的排查里，第一条就是冲着它去的：</p><blockquote><p>检查描述是否包含用户会自然说的关键字。</p></blockquote><p>开头我那个翻车的 commit skill，病根就在这。写的是「Commit message helper」——<strong>这句话里一个「用户会说的词」都没有</strong>。我平时嘴里蹦出来的明明是「帮我提交」「写个 commit」「生成提交信息」，可描述里这些词一个没有，Claude 自然对不上号。后来我让 <code>skill-creator</code> 把描述改成下面这样，再喊一句「帮我提交」，它立马就接住了。</p><p>对照一下这两种写法，差距一目了然：</p><table tabindex="0"><thead><tr><th>❌ 手写常见的废描述</th><th>✅ <code>skill-creator</code> 引导出的好描述</th></tr></thead><tbody><tr><td><code>Commit message helper</code></td><td><code>把暂存的改动总结成一条符合团队规范的 commit message。当用户说「帮我提交」「写个 commit」「生成提交信息」或让你 review 改动准备提交时使用。</code></td></tr><tr><td>只说了「是什么」</td><td><strong>既说「干什么」，又说「什么时候用、用户会怎么说」</strong></td></tr><tr><td>缺触发词，永远不触发</td><td>含真实触发词，该出场时准时出场</td></tr></tbody></table><p>提炼成一句口诀：<strong>好的 description = 干什么 + 什么时候用（含用户会说的那些原话词）</strong>。「干什么」让 Claude 知道这工具是干嘛的，「什么时候用」才是真正的触发钩子——而且这部分要尽量写成<strong>用户嘴里会蹦出来的大白话</strong>，不是你脑子里的术语。</p><p>还有一个反直觉的点，是从 <code>skill-creator</code> 那儿能学到的：<strong>描述要「主动」一点，甚至略微「催」一点</strong>。因为目前 Claude 有个倾向，叫「undertrigger（该用没用）」——它经常在 skill 明明能帮上忙时，懒得调出来。<code>skill-creator</code> 的内部说明里专门叮嘱要对抗这个：</p><blockquote><p>目前 Claude 有不愿触发 skill 的倾向——在 skill 本可派上用场时不去用它。为对抗这一点，请把 skill 描述写得稍微「主动」一些。</p></blockquote><p>什么叫「主动」？举个它给的例子的味道：与其干巴巴写「构建一个展示内部数据的仪表盘」，不如写成「……<strong>只要用户提到仪表盘、数据可视化、内部指标，或者想展示任何公司数据，哪怕没明说要『仪表盘』，都该用这个 skill</strong>」。<strong>把「即使用户没明说，也该出场」的场景显式写进去</strong>——这一手能显著提高它被叫动的概率。</p><p><strong>类比：给店门口的招牌写文案。</strong> 招牌只写「张记」，路人不知道你卖啥，不会进来；写成「张记牛肉面 · 加面免费 · 辣的不辣的都有」，把客人可能搜的词都铺上，进店的人立马多了。<strong><code>description</code> 就是你这个 skill 的招牌——招牌上要有顾客嘴里会念叨的词，还得主动招呼</strong>。</p><blockquote><p>💡 一句话总结：<code>description</code> 是触发总开关，公式是「<strong>干什么 + 什么时候用（含用户会说的原话关键词）</strong>」，而且要写得略微主动、把「没明说也该出场」的场景铺进去——<strong>这一句写好了，skill 才叫得动；写歪了，正文再漂亮也白搭</strong>。</p></blockquote><hr><h2 id="_05-落在哪个目录-个人-skill-vs-项目-skill" tabindex="-1">05 落在哪个目录：个人 skill vs 项目 skill <a class="header-anchor" href="#_05-落在哪个目录-个人-skill-vs-项目-skill" aria-label="Permalink to &quot;05 落在哪个目录：个人 skill vs 项目 skill&quot;">​</a></h2><p>skill 造好了，存哪儿？<strong>存的位置直接决定谁能用到它</strong>。这点 <code>skill-creator</code> 会问你，但你得自己心里有数。</p><p>官方给的位置表，挑出小白最常用的两档：</p><table tabindex="0"><thead><tr><th>位置</th><th>路径</th><th>谁能用</th></tr></thead><tbody><tr><td><strong>个人</strong></td><td><code>~/.claude/skills/&lt;skill-name&gt;/SKILL.md</code></td><td>你电脑上的<strong>所有项目</strong></td></tr><tr><td><strong>项目</strong></td><td><code>.claude/skills/&lt;skill-name&gt;/SKILL.md</code></td><td><strong>仅当前这个项目</strong></td></tr></tbody></table><p>怎么选？就一个判断标准：<strong>这 skill 是「你的私人习惯」还是「这个项目的规矩」？</strong></p><ul><li><strong>你个人到哪都想用的</strong>——比如「按我喜欢的风格写 commit」「把选中文字翻成中文」——放<strong>个人目录</strong>（<code>~/.claude/skills/</code>），一处安家，所有项目通用。</li><li><strong>跟具体项目绑死的</strong>——比如「按本仓库的 API 规范生成接口」「跑这个项目特有的部署流程」——放<strong>项目目录</strong>（<code>.claude/skills/</code>），而且<strong>提交进 Git</strong>，这样团队每个人 clone 下来都自动有这个 skill。</li></ul><p><strong>类比：随身工具包 vs 工地工具房。</strong> 你那把惯用的瑞士军刀，揣兜里走到哪带到哪（个人 skill）；但某个工地专用的大型设备，就锁在那个工地的工具房里，换个工地用不上、也带不走（项目 skill）。<strong>判断依据就是「这工具是跟着人走，还是跟着场子走」</strong>。</p><p>一个简单好记的分法：<strong>通用习惯类全进 <code>~/.claude/skills/</code>，项目专属类进各自的 <code>.claude/skills/</code> 并提交 Git</strong>。像翻译 skill、commit skill 这类，常年待在个人目录，跟着你跑遍所有项目；而每个团队项目里那些「本项目专用」的 skill，一律提交进仓库——<strong>这样新人 clone 完，连 skill 都一起到位了，不用再口头交代「记得装那几个 skill」</strong>。</p><blockquote><p>还有个好处官方点过：项目 skill 会从你的起始目录一路往父目录找，所以你在子目录里启动 Claude，根目录定义的项目 skill 照样能被拾到。monorepo 里各个子包还能有自己的 skill，互不打架。</p></blockquote><blockquote><p>💡 一句话总结：个人 skill 放 <code>~/.claude/skills/</code>、跟着你跑遍所有项目；项目 skill 放 <code>.claude/skills/</code> 并提交 Git、只在本项目生效且团队共享；<strong>判断就一句话——这工具是跟着人走，还是跟着项目走</strong>。</p></blockquote><hr><h2 id="_06-动手-用-skill-creator-起一个最小-skill-并验证触发" tabindex="-1">06 动手：用 <code>skill-creator</code> 起一个最小 skill 并验证触发 <a class="header-anchor" href="#_06-动手-用-skill-creator-起一个最小-skill-并验证触发" aria-label="Permalink to &quot;06 动手：用 \`skill-creator\` 起一个最小 skill 并验证触发&quot;">​</a></h2><p>光看不练假把式。下面带你用 <code>skill-creator</code> 真造一个最小 skill，<strong>最关键的是亲手验证它确实被触发了</strong>——这一步正是手写党最容易跳过、也最容易翻车的地方。全程不依赖任何复杂项目。</p><p>我们造的目标 skill 很小：<strong>让 Claude 把当前 git 仓库里未提交的改动，总结成几条要点</strong>。</p><p><strong>第一步：确认 <code>skill-creator</code> 已就位</strong></p><p>启动 Claude Code 后，敲：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/skills</span></span></code></pre></div><p><strong>预期</strong>：列表里能看到 <code>skill-creator</code>。看不到的话，回第 02 节把 <code>skill-creator</code> 目录拷进 skills 路径装一下（记得开魔法上网）。</p><p><strong>第二步：用大白话让它开造</strong></p><p>在输入框里说清你要什么（顺手把「什么时候触发」也讲了，省得它再追问）：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用 skill-creator 帮我做一个 skill。</span></span>
<span class="line"><span>功能：把当前 git 仓库里未提交的改动总结成 2-3 条要点。</span></span>
<span class="line"><span>触发场景：当我问「我改了啥」「总结一下我的改动」「我这次动了哪些东西」的时候。</span></span>
<span class="line"><span>名字就叫 summarize-changes。</span></span></code></pre></div><p><strong>预期</strong>：<code>skill-creator</code> 被唤起，开始跟你确认意图——可能反问你输出格式、要不要建测试用例。顺着它问的答就行，<strong>重点盯它生成的 <code>description</code> 里有没有把「我改了啥」「总结改动」这些触发词写进去</strong>（这是第 04 节的命根子）。</p><p><strong>第三步：让它把文件落到个人目录</strong></p><p>确认它要把 skill 写到 <code>~/.claude/skills/summarize-changes/</code>（个人目录，所有项目可用）。它生成的 <code>SKILL.md</code> 大概长这样——你重点核对 frontmatter：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">summarize-changes</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">description</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">把当前 git 仓库里未提交的改动总结成几条要点。当用户问「我改了啥」「总结一下我的改动」「我这次动了哪些东西」，或想快速了解工作树现状时使用。</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">## 当前改动</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">!\`git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> diff HEAD\`</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">## 你的任务</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">把上面的改动用 2-3 条要点总结清楚。如果 diff 为空，就说一句「当前没有未提交的改动」。</span></span></code></pre></div><blockquote><p>那行 <code>!\`git diff HEAD\`</code> 是官方的「动态上下文注入」写法：Claude Code 会<strong>先把这条命令跑掉</strong>，把这行替换成真实的 diff，再让 Claude 看到 skill 内容。所以它拿到的是你工作树的实际改动，不是凭空猜的。这个语法 27 篇提过，这里正好用上。</p></blockquote><p><strong>第四步：制造一点改动，好让 skill 有东西可总结</strong></p><p>找任意一个 git 项目（没有就 <code>git init</code> 一个空的），随便改个文件。比如：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/some-git-project</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;// test change&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> README.md</span></span></code></pre></div><p><strong>预期</strong>：<code>git status</code> 能看到 <code>README.md</code> 被改了、处于未提交状态。</p><p><strong>第五步（最关键）：验证它真的被「触发」</strong></p><p>这一步分两种验证，<strong>官方文档明确给了这两条路</strong>：</p><p><strong>验证 A——自动触发</strong>：在 Claude Code 里用大白话问（注意，<strong>别提 skill 名字</strong>，就用自然说法，看它会不会自己想起来）：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>我改了啥？</span></span></code></pre></div><p><strong>预期</strong>：如果 <code>description</code> 写对了，Claude 会<strong>自动调起 <code>summarize-changes</code></strong>，吐出几条改动要点（比如「README.md 末尾新增了一行注释」）。<strong>它能自己接住 = 触发成功，你的 <code>description</code> 关过了</strong>。</p><p><strong>验证 B——直接调用</strong>：万一自动没触发，再用名字硬点一次：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/summarize-changes</span></span></code></pre></div><p><strong>预期</strong>：这次一定会跑，同样吐出改动要点。</p><p><strong>怎么判断成败</strong>：</p><table tabindex="0"><thead><tr><th>现象</th><th>说明</th><th>该咋办</th></tr></thead><tbody><tr><td>验证 A、B 都出要点</td><td>触发完美</td><td>收工</td></tr><tr><td>A 不触发、B 能跑</td><td><strong><code>description</code> 关键词不够</strong>，正文没毛病</td><td>让 <code>skill-creator</code> 优化描述，补触发词</td></tr><tr><td>A、B 都不出要点</td><td>文件没建对 / 正文有问题</td><td>核对路径和 <code>SKILL.md</code> 正文</td></tr></tbody></table><p><strong>重点体会中间那行</strong>——A 不触发但 B 能跑，恰恰证明了本篇的核心论点：<strong>skill 本身没问题，问题在「叫不叫得动」，而叫不动几乎总是 <code>description</code> 的锅</strong>。这正是手写党踩了无数次、却始终没意识到的那个坑。这时让 <code>skill-creator</code> 走一遍「描述优化」就能救回来。</p><p>跑通这五步，你就把「起脚手架 → 写对 description → 落到正确目录 → 制造改动 → 验证自动触发 / 直接调用」这条完整链路亲手验了一遍。<strong>以后造任何 skill，本质都是在这套流程上换内容。</strong></p><blockquote><p>💡 一句话总结：动手就盯两件事——<strong>生成的 <code>description</code> 里有没有真实触发词、用大白话问它会不会自动出场</strong>；自动不触发但 <code>/名字</code> 能跑，就是 <code>description</code> 的锅，让 <code>skill-creator</code> 优化描述补关键词。</p></blockquote><hr><h2 id="_07-一个加分项-打包成-skill-分发给别人" tabindex="-1">07 一个加分项：打包成 <code>.skill</code> 分发给别人 <a class="header-anchor" href="#_07-一个加分项-打包成-skill-分发给别人" aria-label="Permalink to &quot;07 一个加分项：打包成 \`.skill\` 分发给别人&quot;">​</a></h2><p>skill 造好、验过触发，如果你想发给同事或团队，<code>skill-creator</code> 还能帮你<strong>打包成一个 <code>.skill</code> 文件</strong>——对方拿到一个文件就能装，不用你手把手教他建目录。</p><p>它背后跑的是一个打包脚本，你不用记命令，<strong>直接让 <code>skill-creator</code> 帮你打包就行</strong>：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>帮我把这个 skill 打包成 .skill 文件</span></span></code></pre></div><p><strong>预期</strong>：它会运行打包脚本，把整个 <code>summarize-changes/</code> 目录（含 <code>SKILL.md</code> 和所有 <code>scripts/</code>、<code>references/</code>）压成一个 <code>summarize-changes.skill</code> 文件，并告诉你文件路径。</p><p>这一步的意义在于<strong>分发</strong>：上一篇 27 教你「装别人的 skill」，这一篇你造出来的 skill，打包后<strong>正好就是别人那边要装的东西</strong>——一前一后闭环了。团队内部传 skill 通常就是这么干的：谁造了个好用的，打包丢群里，别人下下来一装就有，比口头讲「你照着我这个目录建一下」靠谱多了。</p><blockquote><p>💡 一句话总结：造好的 skill 让 <code>skill-creator</code> 打包成 <code>.skill</code> 文件，<strong>一个文件即可分发</strong>；这恰好接上了 27 篇「装别人的 skill」——你造的，就是别人装的。</p></blockquote><hr><h2 id="_08-小结" tabindex="-1">08 小结 <a class="header-anchor" href="#_08-小结" aria-label="Permalink to &quot;08 小结&quot;">​</a></h2><p>这一篇我们从「为什么别纯手写」一路走到「亲手造一个能触发的 skill」——<strong>核心就一句话：造 skill 的难点不在写文件，在让它叫得动，而 <code>skill-creator</code> 专治这个</strong>。</p><p>把要点串起来回顾：</p><table tabindex="0"><thead><tr><th>你要做的事</th><th>用什么</th><th>关键点</th></tr></thead><tbody><tr><td>装造 skill 的工具</td><td>克隆 / 拷贝目录到 skills 路径</td><td><code>cp -r skill-creator ~/.claude/skills/</code>（独立发布的 skill，非市场内置）</td></tr><tr><td>唤起它开造</td><td><code>/skill-creator</code> 或大白话说需求</td><td>它会反问你「干什么、何时触发」</td></tr><tr><td>让 skill 叫得动</td><td>写好 <code>description</code></td><td>干什么 + 何时用（含用户原话词），略微主动</td></tr><tr><td>选存放位置</td><td>个人 vs 项目目录</td><td>跟着人走放 <code>~/.claude/</code>，跟着项目走放 <code>.claude/</code> 并提交 Git</td></tr><tr><td>确认成败</td><td>自动触发 + <code>/名字</code> 直接调</td><td>自动不触发=description 的锅</td></tr><tr><td>分发给别人</td><td>打包成 <code>.skill</code></td><td>一个文件即可安装，接上 27 篇</td></tr></tbody></table><p><strong>你现在应该能：</strong> 看懂为什么手写 <code>SKILL.md</code> 容易翻在触发上、用 <code>skill-creator</code> 走完「起脚手架 → 写对 description → 测触发 → 打包」整条流程，亲手写出一句「叫得动」的 <code>description</code>，把 skill 放进对的目录，并验证它真的被触发了。<strong>这套「造得对、叫得动」的能力，是你从『用别人的 skill』升级到『打造自己的工具链』的分水岭。</strong></p><p>开头那个翻车的 commit skill，后来用 <code>skill-creator</code> 重造一遍，<strong>前后就改了一句 <code>description</code>，从此再没掉过链子</strong>。这就是这工具最值钱的地方——它不让你多打字，它让你少踩那个看不见的坑。</p><blockquote><p>💡 一句话总结：造 skill 难在触发，<code>skill-creator</code> 把「写对 description、跑测试、照反馈改」这几件手写时容易跳过的事补全了——<strong>会造 skill 的关键，是学会把触发条件说清楚，而不只是把功能写明白</strong>。</p></blockquote><hr><p>下一篇 <strong>29「Agent teams 智能体团队」</strong>（实验性，可能变化）——到这儿为止，你的 Claude Code 一直是「单兵作战」：一个会话、一个助手，你跟它一对一。但有些活儿一个人扛太慢——能不能像组个项目组那样，让<strong>多个智能体分工协作、一个管架构一个写代码一个跑测试</strong>？下一篇就带你从「单兵」迈进「团队作战」。想想看：如果手头能同时有三个 Claude 给你干活，你最先想让它们分头干哪三件事？</p>`,124)])])}const h=t(i,[["render",d]]);export{g as __pageData,h as default};
